// === Arma bus desde tags individuales (v7 - nueva logica lineas/horno/wrap) ===
const incoming = msg.payload || {};
const bus = Object.assign({}, flow.get('bus_raw') || {}, incoming);
flow.set('bus_raw', bus);

const num = (v, fb) => { const n = Number(v); return Number.isFinite(n) ? n : fb; };
const bool = (v) => v === true || v === 1 || v === 'true';

const numeroBotellas = num(bus.NumeroBotellas_ACC, 0);
const numeroBotellasRechazadas = num(bus.NumeroBotellasRechazadas_ACC, 0);
const botellasWrapAcc = num(bus.SeisBotellasWrap_ACC, 0);
const botellasWrapPre = 6;
const paquetesWrapAcc = num(bus.ContadorWrap_ACC, 0);
const paquetesWrapPre = 18;
const botellasWrapDn = bool(bus.SeisBotellasWrap_DN);
const paquetesWrapDn = bool(bus.ContadorWrap_DN);
const hornoOn = bool(bus.HornoON);
const objetoEnHorno = bool(bus.ObjetoEnHorno);
const startCmd = bool(bus.START);
const emergencyOk = bus.EmergencyStop === undefined ? true : bool(bus.EmergencyStop);
const emergencyActive = !emergencyOk;

let lineasStarted = flow.get('lineasStarted') || false;
if (startCmd && emergencyOk) lineasStarted = true;
if (emergencyActive) lineasStarted = false;
flow.set('lineasStarted', lineasStarted);
const lineasEncendidas = lineasStarted && emergencyOk;

let t = flow.get('totals') || {
    botellas: 0,
    paquetes: 0,
    palets: 0,
    lastNumeroBotellas: undefined,
    lastContadorWrapAcc: undefined,
    lastContadorWrapDn: false
};

// NumeroBotellas es el CTU total de botellas que entraron a las lineas.
t.botellas = numeroBotellas;

// Paquetes producidos: acumulamos incrementos de ContadorWrap.ACC y soportamos reset/wrap.
if (typeof t.lastContadorWrapAcc === 'number') {
    if (paquetesWrapAcc > t.lastContadorWrapAcc) {
        t.paquetes += (paquetesWrapAcc - t.lastContadorWrapAcc);
    } else if (paquetesWrapAcc < t.lastContadorWrapAcc && paquetesWrapAcc > 0) {
        t.paquetes += paquetesWrapAcc;
    }
}

// Palets completos por flanco de DN del ContadorWrap.
if (paquetesWrapDn && !t.lastContadorWrapDn) {
    t.palets += 1;
}

t.lastNumeroBotellas = numeroBotellas;
t.lastContadorWrapAcc = paquetesWrapAcc;
t.lastContadorWrapDn = paquetesWrapDn;
flow.set('totals', t);

const data = {
    START: startCmd,
    EmergencyStop: emergencyOk,
    EmergencyActive: emergencyActive,
    LineasEncendidas: lineasEncendidas,
    HornoON: hornoOn,
    ObjetoEnHorno: objetoEnHorno,

    NumeroBotellas_ACC: numeroBotellas,
    NumeroBotellasRechazadas_ACC: numeroBotellasRechazadas,
    SeisBotellasWrap_ACC: botellasWrapAcc,
    SeisBotellasWrap_PRE: botellasWrapPre,
    SeisBotellasWrap_DN: botellasWrapDn,
    ContadorWrap_ACC: paquetesWrapAcc,
    ContadorWrap_PRE: paquetesWrapPre,
    ContadorWrap_DN: paquetesWrapDn,

    // Alias de compatibilidad para widgets/funciones antiguas.
    Caja24_ACC: botellasWrapAcc,
    Caja24_PRE: botellasWrapPre,
    Caja24_DN: botellasWrapDn,
    PaletListo_ACC: paquetesWrapAcc,
    PaletListo_PRE: paquetesWrapPre,
    PaletListo_DN: paquetesWrapDn,
    AlarmaCajaLista: botellasWrapDn,
    AlarmaPaletListo: paquetesWrapDn,
    CajaCompleta: botellasWrapDn || (botellasWrapPre > 0 && botellasWrapAcc >= botellasWrapPre),
    PaletCompleto: paquetesWrapDn || (paquetesWrapPre > 0 && paquetesWrapAcc >= paquetesWrapPre),

    totalLatas: t.botellas,
    totalBotellas: t.botellas,
    totalBotellasRechazadas: numeroBotellasRechazadas,
    totalCajas: t.paquetes,
    totalPaquetes: t.paquetes,
    totalPalets: t.palets,
    ts: Date.now(),
    _updatedTags: Object.keys(incoming)
};
flow.set('plcData', data);
return [{ payload: data }, null];

const cur = msg.payload || {};
const updated = Array.isArray(cur._updatedTags) ? cur._updatedTags : [];
const now = Date.now();

const baseline = () => {
    context.set('alarmLast_SeisBotellasWrap_DN', !!cur.SeisBotellasWrap_DN);
    context.set('alarmLast_ContadorWrap_DN', !!cur.ContadorWrap_DN);
    context.set('alarmLast_ContadorWrap_ACC', Number(cur.ContadorWrap_ACC) || 0);
    context.set('alarmLast_HornoON', !!cur.HornoON);
    context.set('alarmLast_ObjetoEnHorno', !!cur.ObjetoEnHorno);
    context.set('alarmLast_EmergencyStop', !!cur.EmergencyStop);
};

if (flow.get('alarmReset')) {
    flow.set('alarmReset', false);
    baseline();
    flow.set('alarmLog', []);
    context.set('lastPaqueteListoTs', 0);
    context.set('lastPaletListoTs', 0);
    context.set('lastHornoOnTs', 0);
    context.set('lastObjetoHornoTs', 0);
    context.set('lastEmergencyStopTs', 0);
    return [null, { payload: [] }, { payload: false }, { payload: false }];
}

const out = [];
const log = flow.get('alarmLog') || [];
let paqueteLed = null;
let paletLed = null;

function push(tag, mensaje, sev) {
    const entry = { ts: new Date().toLocaleString('es-CO'), epoch: now, tag, mensaje, sev, estado: 'ACTIVA' };
    log.unshift(entry);
    if (log.length > 50) log.pop();
    out.push({ payload: entry });
}
const wasUpdated = (name) => updated.includes(name);
const rose = (name) => {
    if (!wasUpdated(name)) return false;
    const key = 'alarmLast_' + name;
    const previous = context.get(key);
    const current = !!cur[name];
    context.set(key, current);
    return current && previous !== true;
};
const wentFalse = (name) => {
    if (!wasUpdated(name)) return false;
    const key = 'alarmLast_' + name;
    const previous = context.get(key);
    const current = !!cur[name];
    context.set(key, current);
    return current === false && previous !== false;
};
const increased = (name) => {
    if (!wasUpdated(name)) return false;
    const key = 'alarmLast_' + name;
    const previous = context.get(key);
    const current = Number(cur[name]) || 0;
    context.set(key, current);
    return typeof previous === 'number' && current > previous;
};
const debounce = (key, ms) => {
    const previous = context.get(key) || 0;
    if ((now - previous) < ms) return false;
    context.set(key, now);
    return true;
};

const paquetesEnPaletSubieron = increased('ContadorWrap_ACC');
const paqueteListoEvent = rose('SeisBotellasWrap_DN') || paquetesEnPaletSubieron;
const paletCompletoPorConteo = cur.ContadorWrap_PRE > 0 && cur.ContadorWrap_ACC >= cur.ContadorWrap_PRE;
const paletListoEvent = rose('ContadorWrap_DN') || (paquetesEnPaletSubieron && paletCompletoPorConteo);

if (paqueteListoEvent && debounce('lastPaqueteListoTs', 500)) {
    const botellasPorPaquete = Number(cur.SeisBotellasWrap_PRE) || 6;
    push('AlarmaPaqueteListo', 'Paquete completo: ' + botellasPorPaquete + ' botellas listas', 'INFO');
    paqueteLed = { payload: true };
}
if (paletListoEvent && debounce('lastPaletListoTs', 500)) {
    const paquetesPorPalet = Number(cur.ContadorWrap_PRE) || 18;
    push('AlarmaPaletListo', 'Palet completo: ' + paquetesPorPalet + ' paquetes listos', 'ADVERTENCIA');
    paletLed = { payload: true };
}
if (rose('HornoON') && debounce('lastHornoOnTs', 500)) {
    push('AlarmaHornoON', 'Horno encendido', 'INFO');
}
if (rose('ObjetoEnHorno') && debounce('lastObjetoHornoTs', 500)) {
    push('AlarmaPaqueteEnHorno', 'Paquete detectado en el horno', 'ADVERTENCIA');
}
if (wentFalse('EmergencyStop') && debounce('lastEmergencyStopTs', 500)) {
    push('AlarmaEmergencyStop', 'Parada de emergencia activada: circuito abierto', 'CRITICA');
}

flow.set('alarmLog', log);
return [out.length ? out : null, { payload: log }, paqueteLed, paletLed];

const now = Date.now();
const d = msg.payload;

// Buffer rapido (1 h @ 1 Hz) para botellas, rechazadas y paquetes
let hist = flow.get('hist') || [];
const lastFast = hist[hist.length - 1];
if (!lastFast || (now - lastFast.ts) >= 1000) {
    hist.push({
        ts: now,
        botellas: d.totalBotellas ?? d.totalLatas ?? d.NumeroBotellas_ACC ?? 0,
        rechazadas: d.totalBotellasRechazadas ?? d.NumeroBotellasRechazadas_ACC ?? 0,
        paquetes: d.totalPaquetes ?? d.totalCajas ?? 0
    });
    if (hist.length > 3600) hist.shift();   // 1 h * 60 min * 60 seg
    flow.set('hist', hist);
}

// Buffer lento (24h muestreando cada 60s) para palets
let histPalets = flow.get('histPalets') || [];
const lastSlow = histPalets[histPalets.length - 1];
if (!lastSlow || (now - lastSlow.ts) >= 60000) {
    histPalets.push({ ts: now, palets: d.totalPalets ?? 0 });
    if (histPalets.length > 1440) histPalets.shift();   // 24 h * 60 min
    flow.set('histPalets', histPalets);
}

const seriesFast = (name, key, oldKey) => ({
    payload: [{
        series: [name],
        data:   [hist.map(h => ({ x: h.ts, y: h[key] ?? h[oldKey] ?? 0 }))],
        labels: ['']
    }]
});
const seriesSlow = (name, key) => ({
    payload: [{
        series: [name],
        data:   [histPalets.map(h => ({ x: h.ts, y: h[key] ?? 0 }))],
        labels: ['']
    }]
});

return [
    seriesFast('Total botellas', 'botellas', 'latas'),
    seriesFast('Botellas rechazadas', 'rechazadas'),
    seriesFast('Total paquetes', 'paquetes', 'cajas'),
    seriesSlow('Total palets', 'palets')
];

const tag = 'NumeroBotellas.ACC';

const unwrap = (value) => {
    if (value && typeof value === 'object' && value.value !== undefined) return value.value;
    return value;
};

const getValue = (payload) => {
