        if (payload[tag] !== undefined) return unwrap(payload[tag]);
        if (payload.value !== undefined) return payload.value;
        if (payload.payload !== undefined) return unwrap(payload.payload);
    }
    return payload;
};

const n = Number(getValue(msg.payload));
msg.payload = { NumeroBotellas_ACC: Number.isFinite(n) ? n : 0 };
