msg.payload = { EmergencyStop: asBool(getValue(msg.payload)) };
return msg;

// Reset de estado interno del dashboard
const raw = Object.assign({}, flow.get('bus_raw') || {});
raw.EmergencyStop = true;
flow.set('bus_raw', raw);
const rawNumeroBotellas = Number(raw.NumeroBotellas_ACC) || 0;
const rawContadorWrap = Number(raw.ContadorWrap_ACC) || 0;

flow.set('totals', {
