flow.set('hist', []);
flow.set('histPalets', []);
flow.set('alarmLog', []);
flow.set('alarmReset', true);

const data = {
    START: !!raw.START,
    EmergencyStop: true,
    EmergencyActive: false,
    LineasEncendidas: !!flow.get('lineasStarted') && raw.EmergencyStop,
    HornoON: !!raw.HornoON,
    ObjetoEnHorno: !!raw.ObjetoEnHorno,
    NumeroBotellas_ACC: 0,
    NumeroBotellasRechazadas_ACC: 0,
    SeisBotellasWrap_ACC: 0,
    SeisBotellasWrap_PRE: 6,
    SeisBotellasWrap_DN: false,
    ContadorWrap_ACC: 0,
    ContadorWrap_PRE: 18,
