    PaletListo_ACC: 0,
    PaletListo_PRE: 18,
    PaletListo_DN: false,
    CajaCompleta: false,
    PaletCompleto: false,
    totalLatas: 0,
    totalBotellas: 0,
    totalBotellasRechazadas: 0,
    totalCajas: 0,
    totalPaquetes: 0,
    totalPalets: 0,
    ts: Date.now()
};
flow.set('plcData', data);
return [
    { payload: data },
    { payload: [] },
    { payload: [] },
    { payload: false },
    { payload: false }
