const groups = {
    "botellas": "Banda_Transportadora_Hist_Botellas",
    "rechazadas": "Banda_Transportadora_Hist_Rechazadas",
    "paquetes": "Banda_Transportadora_Hist_Paquetes",
    "palets": "Banda_Transportadora_Hist_Palets"
};
const key = msg.topic || msg.payload;
const groupName = groups[key];
if (!groupName) return null;

const state = flow.get('histChartsOpen') || {};
state[key] = !state[key];
flow.set('histChartsOpen', state);

msg.payload = {
    group: state[key]
        ? { show: [groupName], focus: false }
        : { hide: [groupName], focus: false }
};
return msg;

if (msg.payload !== 'connect') return null;
flow.set('histChartsOpen', { botellas: false, rechazadas: false, paquetes: false, palets: false });
msg.payload = {
