        ],
        focus: false
    }
};
return msg;

const tag = 'HornoON';

const unwrap = (value) => {
    if (value && typeof value === 'object' && value.value !== undefined) {
        return value.value;
    }
    return value;
};

const getValue = (payload) => {
    if (payload && typeof payload === 'object') {
        if (payload[tag] !== undefined) return unwrap(payload[tag]);
        if (payload.HornoON !== undefined) return unwrap(payload.HornoON);
