msg.payload = { ObjetoEnHorno: asBool(getValue(msg.payload)) };
return msg;

const body = msg.payload || {};
const texto = (body.texto || body.text || body.comando || body.command || body).toString().trim();
const norm = texto
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9?\s??]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const reply = (payload, statusCode = 200) => ({
    payload,
    statusCode,
    headers: { 'Content-Type': 'application/json' },
    req: msg.req,
    res: msg.res
});

if (!texto) {
    return [null, null, null, null, reply({ status: 'error', respuesta: 'Escribe un comando o una pregunta.' }, 400)];
}

flow.set('ia_ultimo_texto', texto);

const has = (re) => re.test(norm);
const wantsReset = has(/\b(reset|reinicia\w*|reiniciar|restablece\w*|restablecer|libera\w*|liberar|desbloquea\w*|desbloquear|limpia\w*|limpiar)\b/);
const wantsEmergency = has(/\b(emergencia\w*|emergency|paro|parada|stop|alto|deten\w*|detener|detente|frena\w*|frenar|apaga\w*|apagar)\b/);
const wantsStart = has(/\b(start|star|inicia\w*|iniciar|inicio|arranque|arranca\w*|arrancar|enciende\w*|encender|prende\w*|prender|activa\w*|activar)\b/);
const wantsInfo = /[??]/.test(texto)
    || has(/\b(resumen|estado|cuant\w*|cual\w*|dime|muestra|consulta|alarmas?|historico|produccion|descartad\w*)\b/)
    || has(/\besta\b.*\b(linea|horno)\b/)
    || has(/\b(linea|horno)\b.*\besta\b/);

if (wantsReset && !wantsInfo) {
    return [
        null,
        null,
        { payload: true },
        null,
        reply({ status: 'ok', accion: 'reset', respuesta: 'RESET enviado. Emergencia liberada y sistema restablecido.' })
    ];
}

if (wantsEmergency && !wantsInfo) {
    return [
        null,
        { payload: false },
        null,
        null,
        reply({ status: 'ok', accion: 'emergencia', respuesta: 'Parada de emergencia activada. La linea queda detenida hasta realizar RESET.' })
    ];
}

if (wantsStart && !wantsInfo) {
    return [
        { payload: true },
        null,
        null,
        null,
        reply({ status: 'ok', accion: 'start', respuesta: 'START enviado a la linea.' })
    ];
}

msg.ia_texto = texto;
return [null, null, null, msg, null];

const texto = (msg.ia_texto || (msg.payload && (msg.payload.texto || msg.payload.text)) || msg.payload || '').toString().trim();
const plc = flow.get('plcData') || {};
const raw = flow.get('bus_raw') || {};
const totals = flow.get('totals') || {};
const alarmLog = (flow.get('alarmLog') || []).slice(0, 50);
const historial = (flow.get('ia_historial') || []).slice(-6);
const now = Date.now();

const boolText = (v, yes, no) => v ? yes : no;
const contextData = {
    ahora_iso: new Date(now).toISOString(),
    estado: {
        linea: boolText(!!plc.LineasEncendidas, 'activa', 'desactivada'),
        start: !!plc.START,
        emergencyStop: !!plc.EmergencyStop,
        emergenciaActiva: plc.EmergencyActive === true || plc.EmergencyStop === false,
        horno: boolText(!!plc.HornoON, 'encendido', 'apagado'),
        paqueteEnHorno: !!plc.ObjetoEnHorno
    },
    contadores: {
        botellasTotales: Number(plc.totalBotellas ?? plc.NumeroBotellas_ACC ?? totals.botellas ?? 0),
        botellasEnPaquete: Number(plc.SeisBotellasWrap_ACC ?? 0),
        botellasPorPaquete: Number(plc.SeisBotellasWrap_PRE ?? 6),
        paquetesTotales: Number(plc.totalPaquetes ?? totals.paquetes ?? 0),
        paquetesEnPalet: Number(plc.ContadorWrap_ACC ?? 0),
        paquetesPorPalet: Number(plc.ContadorWrap_PRE ?? 18),
        paletsTotales: Number(plc.totalPalets ?? totals.palets ?? 0),
        botellasRechazadas: Number(plc.totalBotellasRechazadas ?? plc.NumeroBotellasRechazadas_ACC ?? raw.NumeroBotellasRechazadas_ACC ?? 0),
