const modelId = env.get('WATSONX_MODEL_ID') || 'meta-llama/llama-4-maverick-17b-128e-instruct-fp8';
if (projectId) projectId = projectId.toString().trim().replace(/[\u0000-\u001F\u007F-\u009F\u200B-\u200F\uFEFF\s'"]/g, '');
if (watsonxUrl) watsonxUrl = watsonxUrl.toString().trim().replace(/\/$/, '');

if (!token || !projectId) {
    const anomaly = /ruido|raro|vibra|vibracion|falla|atasco|atorad|peligro|humo|olor|calent|suena|sonando/i.test(texto);
    const fallback = anomaly
        ? 'IA no disponible aun. Recomendacion operativa: 1) reduce o det?n la alimentacion si aplica. 2) Observa la zona afectada sin exponerte. 3) Si el ruido o riesgo persiste, oprime parada de emergencia. 4) Verifica bandas, rodillos, guias, sensores y acumulacion de botellas o paquetes. 5) Haz reset solo despues de corregir la causa.'
        : 'IA no disponible aun. Estado local: linea ' + contextData.estado.linea + ', emergencia ' + (contextData.estado.emergenciaActiva ? 'activa' : 'normal') + ', botellas ' + contextData.contadores.botellasTotales + ', rechazadas ' + contextData.contadores.botellasRechazadas + ', paquetes ' + contextData.contadores.paquetesTotales + ', palets ' + contextData.contadores.paletsTotales + '.';
    return [null, reply({ status: 'sin_ia', respuesta: fallback, contexto: contextData }, 200)];
}

const systemPrompt = [
    'Eres un asistente SCADA industrial para una linea de botellas, paquetes, palets y horno. Tu trabajo principal es ayudar al operador a decidir que hacer.',
    '',
    'Reglas de respuesta:',
