    '- Responde en espanol, breve, directo y en tono de operador asistente. Para diagnostico usa pasos numerados cortos.'
].join('\n');

const messages = [{ role: 'system', content: systemPrompt }];
historial.forEach(h => {
    messages.push({ role: 'user', content: h.user });
    messages.push({ role: 'assistant', content: h.bot });
});
messages.push({ role: 'user', content: 'Contexto SCADA actual:\n' + JSON.stringify(contextData, null, 2) + '\n\nPregunta del operador: ' + texto });

return [{
    url: watsonxUrl + '/ml/v1/text/chat?version=2024-05-31',
    method: 'POST',
    headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + token,
        'Accept': 'application/json'
    },
    payload: {
        model_id: modelId,
        project_id: projectId,
        messages,
        max_tokens: 700,
        temperature: 0.1,
        top_p: 0.9
    },
    req: msg.req,
    res: msg.res,
    ia_texto: texto,
    ia_context: contextData
}, null];

function reply(payload, statusCode) {
    msg.payload = payload;
    msg.statusCode = statusCode || 200;
    msg.headers = { 'Content-Type': 'application/json' };
    return msg;
}
try {
    const body = msg.payload || {};
    let text = '';
    if (body.choices && body.choices[0] && body.choices[0].message) text = body.choices[0].message.content || '';
    else if (body.results && body.results[0]) text = body.results[0].generated_text || body.results[0].text || '';
    text = String(text || '').trim();
    if (!text) {
        node.error('[IA] Respuesta vacia de watsonx');
        return reply({ status: 'error', respuesta: 'watsonx respondio vacio. Revisa el modelo o las credenciales.' }, 502);
    }
    let h = flow.get('ia_historial') || [];
    h.push({ ts: Date.now(), user: msg.ia_texto || '', bot: text });
    if (h.length > 12) h = h.slice(-12);
    flow.set('ia_historial', h);
    return reply({ status: 'ok', respuesta: text, contexto: msg.ia_context || null }, 200);
} catch (e) {
    node.error('[IA parse] ' + e.message);
    return reply({ status: 'error', respuesta: 'No pude interpretar la respuesta de la IA: ' + e.message }, 500);
}

const plc = flow.get('plcData') || {};
