const apiKey = env.get('IBM_API_KEY');
if (!apiKey) {
    node.error('[IAM] IBM_API_KEY no configurada');
    node.status({ fill: 'red', shape: 'ring', text: 'Sin API Key' });
    return null;
}
node.status({ fill: 'yellow', shape: 'dot', text: 'Solicitando token...' });
return {
    url: 'https://iam.cloud.ibm.com/identity/token',
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Accept': 'application/json' },
    payload: 'grant_type=urn:ibm:params:oauth:grant-type:apikey&apikey=' + encodeURIComponent(apiKey)
};

const body = msg.payload;
if (!body || !body.access_token) {
    node.error('[IAM] Sin access_token');
    node.status({ fill: 'red', shape: 'ring', text: 'Error IAM' });
    return null;
}
flow.set('iam_token', body.access_token);
flow.set('iam_token_time', Date.now());
flow.set('iam_token_expires_in', body.expires_in || 3600);
node.status({ fill: 'green', shape: 'dot', text: 'Token OK' });
return null;

const incoming = msg.payload;
const current = flow.get('vista_unificada') || { data: {}, alarmas: [] };

if (Array.isArray(incoming)) {
    current.alarmas = incoming;
} else if (incoming && typeof incoming === 'object' && incoming.tag && incoming.mensaje) {
    const alarmas = flow.get('alarmLog') || current.alarmas || [];
    current.alarmas = alarmas;
} else if (incoming && typeof incoming === 'object') {
    current.data = Object.assign({}, current.data || {}, incoming);
}

const plcData = flow.get('plcData') || {};
const alarmLog = flow.get('alarmLog');
current.data = Object.assign({}, plcData, current.data || {});
if (Array.isArray(alarmLog)) current.alarmas = alarmLog;
current.ts = Date.now();
flow.set('vista_unificada', current);
msg.payload = current;
return msg;

const tag = 'NumeroBotellasRechazadas.ACC';

const unwrap = (value) => {
    if (value && typeof value === 'object' && value.value !== undefined) return value.value;
    return value;
};

const getValue = (payload) => {
    if (payload && typeof payload === 'object') {
        if (payload[tag] !== undefined) return unwrap(payload[tag]);
        if (payload.value !== undefined) return payload.value;
        if (payload.payload !== undefined) return unwrap(payload.payload);
    }
    return payload;
};

const n = Number(getValue(msg.payload));
msg.payload = { NumeroBotellasRechazadas_ACC: Number.isFinite(n) ? n : 0 };
return msg;

const alarmas = flow.get('alarmLog') || [];
const delimiter = ';';
const headers = ['Timestamp', 'Epoch', 'Tag', 'Mensaje', 'Severidad', 'Estado'];

const clean = (value) => {
    if (value === null || value === undefined) return '';
    return String(value).replace(/\r?\n/g, ' ').trim();
};

const csvCell = (value) => {
    const text = clean(value);
    const escaped = text.replace(/"/g, '""');
    return /[";\r\n]/.test(escaped) ? '"' + escaped + '"' : escaped;
};

const rows = alarmas.map(a => [
    a.ts || '',
    a.epoch || a.time || '',
    a.tag || '',
    a.mensaje || '',
    a.sev || a.severidad || '',
    a.estado || 'ACTIVA'
]);

const lines = [headers, ...rows].map(row => row.map(csvCell).join(delimiter));
const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');

msg.headers = {
    'Content-Type': 'text/csv; charset=utf-8',
    'Content-Disposition': 'attachment; filename="alarmas_scada_' + stamp + '.csv"',
    'Cache-Control': 'no-store'
};
msg.payload = '\ufeff' + lines.join('\r\n');
return msg;
